INSERT INTO `v1_81d453b10cb1d8e00703478940bf3b9d02909fc2493abee3378854d04f8813fc` VALUES ("", "確かにね…それに\nこうなった理由も\n分かるかも", "", "", 1010026, 10, 112531, 11, "", "", 1);
INSERT INTO `v1_81d453b10cb1d8e00703478940bf3b9d02909fc2493abee3378854d04f8813fc` VALUES ("", "", "", "", 1010027, "", 0, 91, "", "", 1);
INSERT INTO `v1_81d453b10cb1d8e00703478940bf3b9d02909fc2493abee3378854d04f8813fc` VALUES ("", "ま、興味はあるし\n付き合ってあげるわ", "", "", 1010028, 10, 106031, 11, "", "", 1);
